<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';$pdo=obtenerConexion();$estado=in_array($_GET['estado']??'', ['nuevo','revisado','cerrado'],true)?$_GET['estado']:'';$sql='SELECT e.*,m.texto seccion FROM menu_formulario_envios e JOIN menu_sitio m ON m.id=e.menu_id'.($estado?' WHERE e.estado=:estado':'').' ORDER BY e.created_at DESC LIMIT 250';$q=$pdo->prepare($sql);$q->execute($estado?['estado'=>$estado]:[]);$filas=$q->fetchAll();cmsCabecera('Respuestas de formularios','navbar/index.php','Consulta los envíos recibidos desde las secciones dinámicas.');?>
<div class="card card-rounded"><div class="card-body"><div class="d-flex flex-wrap gap-2 mb-3"><a class="btn btn-light" href="index.php">Volver</a><?php foreach([''=>'Todas','nuevo'=>'Nuevas','revisado'=>'Revisadas','cerrado'=>'Cerradas']as$e=>$label):?><a class="btn btn-sm <?=$estado===$e?'btn-primary':'btn-outline-primary'?>" href="?estado=<?=$e?>"><?=$label?></a><?php endforeach;?></div><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Sección</th><th>Datos</th><th>Fecha</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php if(!$filas):?><tr><td colspan="5" class="text-center text-muted py-5">No hay respuestas.</td></tr><?php endif;?><?php foreach($filas as$f):$datos=datosContenidoNavbarAtenea($f['datos_json']);?><tr><td><?=atenea_e($f['seccion'])?></td><td><?php foreach($datos as$k=>$v):?><div><strong><?=atenea_e(ucfirst($k))?>:</strong> <?=atenea_e($v)?></div><?php endforeach;?></td><td><?=atenea_e($f['created_at'])?></td><td><span class="badge bg-secondary"><?=atenea_e($f['estado'])?></span></td><td><form method="post" action="formulario-accion.php" class="d-flex gap-1"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$f['id']?>"><button class="btn btn-sm btn-outline-success" name="estado" value="revisado">Revisada</button><button class="btn btn-sm btn-outline-secondary" name="estado" value="cerrado">Cerrar</button></form></td></tr><?php endforeach;?></tbody></table></div></div></div><?php cmsPie(); ?>
